mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_company
    WHERE company_id = #{companyId}
      AND active = TRUE
)

SELECT partner_id, partner_name, partner_type, partner_role, phone, active FROM tb_trade_partner WHERE company_id = #{companyId}
AND active = #{active}
AND ( partner_role = #{partnerRole} OR partner_role = 'BOTH' )
AND ( partner_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY partner_name ASC, partner_id ASC LIMIT #{limit}
